     1→import { produce } from 'immer';
     2→
     3→import { defineFunctionName } from '../helpers/function';
     4→import {
     5→  assertObject,
     6→  getProperty,
     7→  objectEntries,
     8→  requireAll,
     9→} from '../helpers/object-utils';
    10→import { capitalize } from '../helpers/string-utils';
    11→
    12→import type { AnyRecord } from '../helpers/type-utils';
    13→
    14→import { createModel, createType, InferType } from '../schema';
    15→
    16→import { Cache } from './cache';
    17→import {
    18→  AsyncSliceState,
    19→  CreateAsyncSlice,
    20→  CreateSlice,
    21→  MachineAction,
    22→  MachineReducer,
    23→  MachineSliceInfo,
    24→  MachineSlices,
    25→  MachineState,
    26→  RuntimeActionCreator,
    27→  SliceContext,
    28→  SliceKind,
    29→  SliceReducer,
    30→  StringTypes,
    31→} from './models';
    32→
    33→export namespace Slices {
    34→  export type SliceMapReducer = MachineReducer & { info: MachineSliceInfo };
    35→  // prettier-ignore
    36→  export type SliceMap = {
    37→    reducer: SliceMapReducer;
    38→    actionCreatorByType: { [K in StringTypes.ActionType]: RuntimeActionCreator };
    39→    actionCreatorListBySliceKey: { [K in StringTypes.SliceKey]: RuntimeActionCreator[] };
    40→    actionCreatorsSliceKey: { [K in StringTypes.SliceKey]: { [K: string]: RuntimeActionCreator } };
    41→    actionTypesBySliceKey: { [K in StringTypes.SliceKey]: { [K: string]: string } };
    42→    reducerBySliceKey: { [K: StringTypes.SliceKey]: SliceMapReducer };
    43→    reducerByActionType: { [K in StringTypes.ActionType]: SliceMapReducer };
    44→    actionTypeList: StringTypes.ActionType[];
    45→  };
    46→  export type SyncSliceModel = InferType<typeof SyncSliceModel>;
    47→  export type AsyncSliceModel = InferType<typeof AsyncSliceModel>;
    48→  export type SlicesMap = Omit<SliceMap, 'reducer'> & {
    49→    info: MachineSliceInfo[];
    50→    mergedSlicesInitialContext: SliceContext;
    51→    mergedSlicesInitialState: AnyRecord;
    52→  };
    53→
    54→  export const SyncSliceModel = createModel({
    55→    id: 'string',
    56→    kind: { enum: [SliceKind.sync] },
    57→    initial: 'unknown',
    58→    reducers: { record: 'function' },
    59→    cache: Cache.Model,
    60→  });
    61→
    62→  export const AsyncSliceModel = createModel({
    63→    id: 'string',
    64→    kind: { enum: [SliceKind.async] },
    65→    initial: 'any',
    66→    load: 'function',
    67→    context: 'object',
    68→    cache: Cache.Model,
    69→  });
    70→
    71→  export const AnySliceModel = createType({
    72→    union: [
    73→      SyncSliceModel,
    74→      AsyncSliceModel,
    75→    ],
    76→  });
    77→
    78→  export function IsSyncSliceKind(value: unknown): value is SyncSliceModel {
    79→    assertObject(value);
    80→    return SyncSliceModel.isValid(value);
    81→  }
    82→
    83→  export function IsAsyncSliceKind(value: unknown): value is AsyncSliceModel {
    84→    assertObject(value);
    85→    return AsyncSliceModel.isValid(value);
    86→  }
    87→
    88→  export const AsyncReducerNames = new Set([
    89→    'load',
    90→    'success',
    91→    'fail',
    92→    'clear',
    93→  ] as const);
    94→
    95→  /**
    96→   * Maps one slice to internal machine utils
    97→   * @param machineID
    98→   * @param map
    99→   * @constructor
   100→   */
   101→  export function MapSlice(machineID: string, map: MachineSliceInfo): SliceMap {
   102→    const { sliceKey, slice, actionPrefix } = map;
   103→    let reducer = null as SliceMapReducer | null;
   104→    const actionCreatorByType = {} as SlicesMap['actionCreatorByType'];
   105→    const reducerByActionType = {} as SlicesMap['reducerByActionType'];
   106→    // prettier-ignore
   107→    const actionCreatorListBySliceKey = {} as SlicesMap['actionCreatorListBySliceKey'];
   108→    const actionCreatorsSliceKey = {} as SlicesMap['actionCreatorsSliceKey'];
   109→    const actionTypesBySliceKey = {} as SlicesMap['actionTypesBySliceKey'];
   110→    const actionTypeList = [] as SlicesMap['actionTypeList'];
   111→
   112→    const namePrefix = `${machineID}${capitalize(sliceKey)}`;
   113→
   114→    function registerAction(
   115→      reducerName: StringTypes.SliceReducerName,
   116→    ): RuntimeActionCreator {
   117→      const actionType =
   118→        `${actionPrefix}${reducerName}` as StringTypes.ActionType;
   119→
   120→      function action(payload: unknown): MachineAction {
   121→        return {
   122→          type: actionType,
   123→          payload,
   124→        };
   125→      }
   126→
   127→      defineFunctionName(
   128→        action,
   129→        `${namePrefix}${capitalize(reducerName)}RuntimeActionCreator`,
   130→      );
   131→      action.info = map;
   132→      action.type = actionType;
   133→      action.sliceReducerName = reducerName;
   134→      actionCreatorByType[actionType] = action;
   135→      actionTypeList.push(actionType);
   136→      // prettier-ignore
   137→      actionCreatorListBySliceKey[sliceKey] = actionCreatorListBySliceKey[sliceKey] || [];
   138→      actionCreatorsSliceKey[sliceKey] = actionCreatorsSliceKey[sliceKey] || {};
   139→      actionTypesBySliceKey[sliceKey] = actionTypesBySliceKey[sliceKey] || {};
   140→      actionTypesBySliceKey[sliceKey][reducerName] = actionType;
   141→      actionCreatorListBySliceKey[sliceKey].push(action);
   142→      actionCreatorsSliceKey[sliceKey][reducerName] = action;
   143→      return action;
   144→    }
   145→
   146→    if (IsAsyncSliceKind(slice)) {
   147→      AsyncReducerNames.forEach(name => {
   148→        return registerAction(name as StringTypes.SliceReducerName);
   149→      });
   150→
   151→      const fn = function reducer(
   152→        state = slice.initial as MachineState,
   153→        action: MachineAction,
   154→      ) {
   155→        // prettier-ignore
   156→        const localAction = actionCreatorByType[action.type as StringTypes.ActionType];
   157→        if (!localAction) return state;
   158→
   159→        const sliceReducerName = localAction.sliceReducerName;
   160→
   161→        return produce(state, draft => {
   162→          switch (sliceReducerName) {
   163→            case 'load': {
   164→              draft.loading = true;
   165→              draft.failed = false;
   166→              draft.error = null;
   167→              break;
   168→            }
   169→            case 'success': {
   170→              draft.loading = false;
   171→              draft.loaded = true;
   172→              draft.value = action.payload;
   173→              break;
   174→            }
   175→            case 'fail': {
   176→              const error = getProperty(action.payload, 'error', true);
   177→              draft.loading = false;
   178→              draft.failed = true;
   179→              draft.error = error as string;
   180→              break;
   181→            }
   182→            case 'clear': {
   183→              return slice.initial;
   184→            }
   185→            default: {
   186→              return draft;
   187→            }
   188→          }
   189→        });
   190→      };
   191→      fn.info = map;
   192→      reducer = fn;
   193→    } else if (IsSyncSliceKind(slice)) {
   194→      const sliceReducersByActionTypes = new Map<string, SliceReducer>();
   195→
   196→      objectEntries(slice.reducers).forEach(([name, sliceReducer]) => {
   197→        const { type } = registerAction(name as StringTypes.SliceReducerName);
   198→        sliceReducersByActionTypes.set(type, sliceReducer);
   199→      });
   200→
   201→      const fn = function reducer(
   202→        state = slice.initial as MachineState,
   203→        action: MachineAction,
   204→      ) {
   205→        const reducer = sliceReducersByActionTypes.get(action.type);
   206→        if (!reducer) return state;
   207→        return produce(state, draft => {
   208→          return reducer(draft, action.payload);
   209→        });
   210→      };
   211→      fn.info = map;
   212→      reducer = fn;
   213→    } else {
   214→      AnySliceModel.parse(slice);
   215→    }
   216→
   217→    if (typeof reducer !== 'function') {
   218→      throw new Error(`Failed to create reducer from slice "${sliceKey}".`);
   219→    }
   220→
   221→    actionTypeList.forEach(actionType => {
   222→      reducerByActionType[actionType] = reducer;
   223→    });
   224→
   225→    defineFunctionName(reducer, `${machineID}${sliceKey}Reducer`);
   226→
   227→    return {
   228→      reducer,
   229→      reducerBySliceKey: { [sliceKey]: reducer },
   230→      actionCreatorsSliceKey,
   231→      actionCreatorListBySliceKey,
   232→      actionCreatorByType,
   233→      reducerByActionType,
   234→      actionTypesBySliceKey,
   235→      actionTypeList,
   236→    };
   237→  }
   238→
   239→  /**
   240→   * Maps multiples slices to machine internal utils
   241→   * @param machineID
   242→   * @param slices
   243→   * @constructor
   244→   */
   245→  export function MapSlices(
   246→    machineID: string,
   247→    slices: MachineSlices,
   248→  ): SlicesMap {
   249→    const reducersMap: SlicesMap = {
   250→      info: [],
   251→      actionTypeList: [],
   252→      actionTypesBySliceKey: {},
   253→      mergedSlicesInitialContext: {},
   254→      mergedSlicesInitialState: {},
   255→      actionCreatorByType: {},
   256→      reducerByActionType: {},
   257→      reducerBySliceKey: {},
   258→      actionCreatorListBySliceKey: {},
   259→      actionCreatorsSliceKey: {},
   260→    };
   261→
   262→    const prefix = `@${machineID}/` as const;
   263→
   264→    // prettier-ignore
   265→    Object.entries(slices).forEach(([sliceKey, slice]) => {
   266→      const info = {sliceKey: sliceKey as StringTypes.SliceKey, slice, actionPrefix: `${prefix}${slice.id}/`};
   267→      const map = MapSlice(machineID, info);
   268→      const initial = IsSyncSliceKind(slice) ? slice.initial : AsyncInitialState(null)
