import { Static, TSchema } from 'typebox';
import { IsUnknown, NullableToPartial, Paths } from '../helpers/type-utils';

/**
 * Core type definitions and public interfaces for the type validation system.
 * This file establishes the contract for creating and interacting with types.
 */

export type AllTypes = {
  string: {};
  number: {};
  null: {};
  undefined: {};
  boolean: {};
  unknown: {};
  any: {};
  object: { properties: ObjectTypeProperties };
  enum: { enum: ReadonlyArray<string> };
  list: { items: TypeDefinition };
  union: { union: ReadonlyArray<TypeDefinition> };
  record: { record: TypeDefinition };
  date: {};
  function: {};
  type: { '~typebox': TSchema };
};

export type ObjectTypeProperties = { [K: string]: TypeDefinition };

export type TypeName = keyof AllTypes & {};

/**
 * Represents a type definition using a compact string format.
 * The format is: `typeName[?][[]][?]`.
 * - `typeName`: The base type (e.g., 'string', 'number').
 * - `?` (optional, first): Marks the value as optional (e.g., 'string?').
 * - `[]` (optional): Marks the type as an array (e.g., 'string[]').
 * - `?` (optional, second): Marks the array itself as optional (e.g., 'string[]?').
 */
export type TypeDefinitionString =
  `${TypeName}${'?' | ''}${'[]' | ''}${'?' | ''}`;

/**
 * Represents a type definition using an object-based format, for objects,
 * enums, lists, or for providing a raw `typebox` type.
 */
export type ObjectBasedTypeDefinition =
  | AllTypes['object']
  | AllTypes['enum']
  | AllTypes['list']
  | AllTypes['union']
  | AllTypes['record']
  | AllTypes['type']
  | _TypeBoxSchema<any>;

/**
 * A union of all possible ways to define a type for `createType`.
 * It can be a compact string or a more descriptive object.
 */
export type TypeDefinition = TypeDefinitionString | ObjectBasedTypeDefinition;

export type FunctionLike = (...params: ReadonlyArray<any>) => any;

/**
 * Represents a compiled type created by `createType`.
 * Provides methods for validation, parsing, and type checking.
 * @template Definition The original definition used to create the type.
 */
export type Type<
  Definition extends TypeDefinition,
  Result = InferType<Definition>,
> = {
  /**
   * The underlying `typebox` schema. Useful for advanced integrations or extensions.
   */
  '~typebox': NoInfer<_TypeBoxSchema<Result>>;
  /**
   * Creates and caches a new `Type` that represents an array of the current type.
   * @returns A `Type` instance for an array of the type.
   */
  list(): Type<_TypeBoxSchema<Result[]>>;
  /**
   * Validates and parses the input value against the type.
   * Throws a `ValidationError` if the validation fails.
   * @param value The value to parse.
   * @param property An optional path string to extract a nested value before parsing.
   * @returns The validated and typed value.
   */
  parse<T>(value: T, property?: Paths<T>): Result;
  /**
   * Validates and parses an array of values against the type.
   * Throws a `ValidationError` if the validation fails.
   * @param value The array to parse.
   * @param property An optional path string to extract a nested array before parsing.
   * @returns The validated and typed array.
   */
  parseList<T>(value: T, property?: Paths<T>): Result[];
  /**
   * A type guard that checks if a value is valid against the type.
   * @param value The value to check.
   * @returns `true` if the value is valid, otherwise `false`.
   */
  isValid(value: unknown): value is Result;
  /**
   * A type guard that checks if a value is a valid array of the type.
   * @param value The value to check.
   * @returns `true` if the value is a valid array, otherwise `false`.
   */
  isValidList(value: unknown): value is Result[];
};

/**
 * Infers the static TypeScript type from a `TypeDefinition`.
 * This is useful for declaring types.
 *
 * @example
 * const MySchema = createType({ properties: { name: 'string' } });
 * type TMySchema = InferType<typeof MySchema>; // { name: string }
 */
export type InferType<T> =
  T extends _TypeBoxSchema<any> ? Static<T> : _InferType<T>;

export type _InferType<T> = T extends { __outputType: infer Expected }
  ? Expected
  : T extends { '~typebox': infer TT }
    ? NullableToPartial<InferType<TT>>
    : T extends TypeDefinition
      ? InferType<T>
      : NullableToPartial<{
          [K in keyof T]: T[K] extends { __outputType: infer Expected }
            ? Expected
            : InferType<T[K]>;
        }>;

/**
 * Represents any typebox type that validates the type `Expected`
 */
export type _TypeBoxSchema<Expected> =
  IsUnknown<Expected> extends [true] ? TSchema : TSchema & { static: Expected };

