     1→import _getProperty from 'lodash/get';
     2→import _isPlainObject from 'lodash/isPlainObject';
     3→import _setProperty from 'lodash/set';
     4→
     5→import {
     6→  assertErrorLike,
     7→  invariant,
     8→  InvariantError,
     9→  moveStackTrace,
    10→  tryCatch,
    11→} from './error-utils';
    12→
    13→import { capitalize } from './string-utils';
    14→import {
    15→  AsString,
    16→  BuiltIn,
    17→  CastUnknown,
    18→  Compute,
    19→  Falsy,
    20→  isFalsy,
    21→  ObjectEntries,
    22→  Paths,
    23→  PathType,
    24→  UnionToIntersection,
    25→  UnknownRecord,
    26→  Writable,
    27→} from './type-utils';
    28→import { getTypeOf } from './typeof';
    29→
    30→/**
    31→ * Utils to handle object and object paths
    32→ * Some example of object paths:
    33→ * - considering a User object:
    34→ *  - 'user.id';
    35→ *  - 'user.address.street';
    36→ *  - 'user.address';
    37→ */
    38→
    39→/**
    40→ * extract object keys with type inference
    41→ */
    42→export function objectKeys<Obj extends object>(
    43→  value: Obj,
    44→): Extract<keyof Obj, string>[] {
    45→  try {
    46→    return Object.keys(value) as never;
    47→  } catch (e) {
    48→    assertErrorLike(e);
    49→    throw moveStackTrace(e, objectKeys);
    50→  }
    51→}
    52→
    53→export function objectMap<const O extends {}>(
    54→  object: O,
    55→): ObjectEntries<Writable<O>> & Writable<O> {
    56→  const list = objectEntries(object);
    57→  const proxyTarget = { ...object };
    58→  Object.setPrototypeOf(proxyTarget, Object.getPrototypeOf(list));
    59→
    60→  list.forEach((value, idx) => {
    61→    Object.defineProperty(proxyTarget, idx, {
    62→      value,
    63→      enumerable: false,
    64→      configurable: false,
    65→    });
    66→  });
    67→
    68→  return new Proxy(proxyTarget, {
    69→    get(target, prop, receiver) {
    70→      const value = Reflect.get(target, prop, receiver);
    71→
    72→      if (typeof value === 'function') {
    73→        function fn(...args: any[]) {
    74→          const value = Reflect.get(target, prop, receiver) as never;
    75→          return Reflect.apply(value, list, args);
    76→        }
    77→        const name = Object.getOwnPropertyDescriptor(list, prop);
    78→        if (name) Object.defineProperties(fn, { name });
    79→        return fn;
    80→      }
    81→
    82→      return value;
    83→    },
    84→  }) as never;
    85→}
    86→
    87→export function objectEntries<O extends object>(init: O): ObjectEntries<O> {
    88→  return Object.entries(init) as never;
    89→}
    90→
    91→export function objectValues<O extends object>(init: O): O[keyof O][] {
    92→  return Object.values(init) as any;
    93→}
    94→
    95→/**
    96→ * Checks if value is a plain object, that is, an object created by the
    97→ * Object constructor or one with a [[Prototype]] of null.
    98→ */
    99→export function isObject(value: unknown): value is UnknownRecord {
   100→  return _isPlainObject(value);
   101→}
   102→
   103→export function assertObject(
   104→  value: unknown,
   105→  message?: string,
   106→  parent?: Function,
   107→): asserts value is UnknownRecord {
   108→  if (isObject(value)) return;
   109→
   110→  message =
   111→    message ??
   112→    `Expected value to be an object; found ${getTypeOf(value)} instead.`;
   113→  throw new InvariantError(message, parent ?? assertObject, { value });
   114→}
   115→
   116→/**
   117→ * Get value from an object path.
   118→ * It will assert against 'falsy' values unless configured to accept.
   119→ * Any value that matches `Boolean(value) === false` is falsy.
   120→ *
   121→ * @example:
   122→ * - getValue(value, 'user.id'); // => string;
   123→ * - getValue(value, 'user.id', true); // => string|null|undefined;
   124→ * @param object
   125→ * @param path
   126→ * @param allowFalsyValues
   127→ */
   128→
   129→export function getProperty<Obj, OPath extends Paths<Obj>>(
   130→  object: Obj,
   131→  path: CastUnknown<OPath, string>,
   132→  allowFalsyValues: false, // default mode
   133→): Exclude<PathType<Obj, OPath>, Falsy>;
   134→
   135→export function getProperty<Obj, OPath extends Paths<Obj>>(
   136→  object: Obj,
   137→  path: CastUnknown<OPath, string>,
   138→): Exclude<PathType<Obj, OPath>, Falsy>;
   139→
   140→export function getProperty<Obj, OPath extends Paths<Obj>>(
   141→  object: Obj,
   142→  path: CastUnknown<OPath, string>,
   143→  allowFalsyValues: true,
   144→): PathType<Obj, OPath> | null | undefined;
   145→
   146→export function getProperty<Obj, OPath extends Paths<Obj>>(
   147→  object: Obj,
   148→  path: CastUnknown<OPath, string>,
   149→  allowFalsyValues: boolean = false,
   150→): PathType<Obj, OPath> | null | undefined {
