     5→import {
     6→  CachePolicy,
     7→  CacheStrategy,
     8→  CacheStrategyField,
     9→  MachineMetadata,
    10→  MachineSliceInfo,
    11→  MachineUserID,
    12→  SliceContext,
    13→  StringTypes,
    14→} from './models';
    15→
    16→import { objectKeys } from '../helpers/object-utils';
    17→import { createModel } from '../schema';
    18→import { Slices } from './slice';
    19→
    20→export namespace Cache {
    21→  /**
    22→   * @internal
    23→   * @private
    24→   */
    25→  export type Invalidation = {
    26→    sliceKey: StringTypes.SliceKey;
    27→    reason:
    28→      | CacheStrategyField
    29→      | `${CacheStrategyField}ConfigMismatch`
    30→      | 'unknown';
    31→    configValue: CacheStrategy[CacheStrategyField] | null;
    32→    cachedComparedValue: string | number | null | undefined;
    33→    currentComparedValue: string | number | null | undefined;
    34→    details?: string;
    35→  };
    36→
    37→  export function IsStaleByTTL(
    38→    cacheStrategy: CacheStrategy,
    39→    cachedMetadata: MachineMetadata,
    40→  ): boolean {
    41→    const { ttl: ttlConfig } = cacheStrategy;
    42→    const { updatedAt: cachedUpdatedAt } = cachedMetadata;
    43→
    44→    if (ttlConfig !== undefined) {
    45→      const ttlMS = ms(ttlConfig);
    46→      const elapsed = Date.now() - cachedUpdatedAt;
    47→      if (ttlMS === 0 || (ttlMS > 0 && elapsed > ttlMS)) {
    48→        return true;
    49→      }
    50→    }
    51→    return false;
    52→  }
    53→
    54→  /**
    55→   * @internal
    56→   * @private
    57→   */
    58→  export type SliceInvalidation = {
    59→    sliceKey: StringTypes.SliceKey;
    60→    invalidations: Invalidation[];
    61→    invalidatedBy: Invalidation['reason'][];
    62→  };
    63→
    64→  export function GetInvalidations(params: {
    65→    mappedSlice: MachineSliceInfo;
    66→    cachedMetadata: MachineMetadata;
    67→    currentUserID: MachineUserID;
    68→    currentSessionID: string;
    69→  }): SliceInvalidation | null {
    70→    const {
    71→      //
    72→      currentSessionID,
    73→      mappedSlice,
    74→      currentUserID,
    75→      cachedMetadata,
    76→    } = params;
    77→
    78→    const { sliceKey, slice } = mappedSlice;
    79→
    80→    const {
    81→      updatedAt: cachedUpdatedAt,
    82→      userID: cacheUserID,
    83→      sessionID: cacheSessionID,
    84→      slicesCacheStrategy: cachedSlicesCacheStrategy,
    85→    } = cachedMetadata;
    86→
    87→    const oldSliceStrategy = cachedSlicesCacheStrategy?.[sliceKey];
    88→
    89→    const currentSliceStrategy = slice['cache'];
    90→
    91→    const invalidations: SliceInvalidation = {
    92→      sliceKey,
    93→      invalidatedBy: [],
    94→      invalidations: [],
    95→    };
    96→
    97→    const push = (item: Invalidation) => {
    98→      invalidations.invalidations.push(item);
    99→      invalidations.invalidatedBy.push(item.reason);
   100→    };
   101→
   102→    if (oldSliceStrategy) {
   103→      const allKeys = new Set([
   104→        ...Object.keys(oldSliceStrategy),
   105→        ...Object.keys(currentSliceStrategy),
   106→      ]) as Set<keyof CacheStrategy>;
   107→
   108→      for (let key of allKeys) {
   109→        if (
   110→          key !== 'swr' &&
   111→          oldSliceStrategy[key] !== currentSliceStrategy[key]
   112→        ) {
   113→          push({
   114→            sliceKey,
   115→            reason: `${key}ConfigMismatch`,
   116→            configValue: currentSliceStrategy[key] as never,
   117→            currentComparedValue: null,
   118→            cachedComparedValue: null,
   119→          });
   120→        }
   121→      }
   122→    } else {
   123→      push({
   124→        sliceKey,
   125→        reason: 'unknown',
   126→        configValue: null,
   127→        currentComparedValue: null,
   128→        cachedComparedValue: null,
   129→        details: `cachedSlicesCacheStrategy?.["${sliceKey}"] is undefined.`,
   130→      });
   131→    }
   132→
   133→    if (currentSliceStrategy['ttl'] !== undefined) {
   134→      if (IsStaleByTTL(currentSliceStrategy, cachedMetadata)) {
   135→        push({
   136→          sliceKey,
   137→          reason: 'ttl',
   138→          configValue: currentSliceStrategy['ttl'],
   139→          currentComparedValue: Date.now(),
   140→          cachedComparedValue: cachedUpdatedAt,
   141→        });
   142→      }
   143→    }
   144→
   145→    const { policy } = currentSliceStrategy;
   146→
   147→    switch (policy) {
   148→      case 'public': {
   149→        break; // already validated by ttl, above.
   150→      }
   151→
   152→      case 'session': {
   153→        if (cacheSessionID !== currentSessionID) {
   154→          push({
   155→            sliceKey,
   156→            reason: 'policy',
   157→            configValue: policy,
   158→            currentComparedValue: currentSessionID,
   159→            cachedComparedValue: cacheSessionID,
   160→          });
   161→        }
   162→        break;
   163→      }
   164→
   165→      case 'private': {
   166→        if (currentUserID !== cacheUserID) {
   167→          push({
   168→            sliceKey,
   169→            reason: 'policy',
   170→            configValue: policy,
   171→            currentComparedValue: currentUserID,
   172→            cachedComparedValue: cacheUserID,
   173→          });
   174→        }
   175→        break;
   176→      }
   177→
   178→      default: {
   179→        const message = `GetCacheInvalidations found invalid policy: ${policy}`;
   180→        devLog(new Error(message));
   181→        break;
   182→      }
   183→    }
   184→
   185→    return invalidations.invalidations.length ? invalidations : null;
   186→  }
   187→
   188→  export type StateInvalidationsReport<T = AnyRecord> = {
   189→    cleanState: T;
   190→    stale: StringTypes.SliceKey[];
   191→    reset: StringTypes.SliceKey[];
   192→    invalidations: SliceInvalidation[];
   193→  };
   194→
   195→  export function StateInvalidations<T extends AnyRecord>(params: {
   196→    mappedSlices: Slices.SlicesMap;
   197→    getContext: () => SliceContext;
   198→    cachedState: T;
   199→    currentSessionID: string;
   200→    cachedMetadata: MachineMetadata;
   201→  }): StateInvalidationsReport<T> {
   202→    const {
   203→      getContext,
   204→      mappedSlices,
   205→      currentSessionID,
   206→      cachedState,
   207→      cachedMetadata,
   208→    } = params;
   209→
   210→    const result: StateInvalidationsReport<T> = {
   211→      reset: [],
   212→      stale: [],
   213→      cleanState: { ...cachedState },
   214→      invalidations: [],
   215→    };
   216→
   217→    mappedSlices.info.forEach(mappedSlice => {
   218→      const { sliceKey, slice } = mappedSlice;
   219→
   220→      if (!(sliceKey in cachedState)) return;
   221→
   222→      const cacheInvalidations = GetInvalidations({
   223→        currentSessionID,
   224→        mappedSlice,
   225→        currentUserID: getContext().userID,
   226→        cachedMetadata,
   227→      });
