export function reduce<Result, const Item>(
  items: ReadonlyArray<Item>,
  reducer: (next: Item) => Partial<Result> | undefined,
): Result {
  return items.reduce((acc, entry) => {
    const next = reducer(entry);
    return {
      ...acc,
      ...next,
    };
  }, {} as Result);
}

