export * from './helpers';
export * from './machine';
export * from './models';
export * from './slice';

export type { Store } from './store';

/**
 * @file This file contains general-purpose utility types.
 */

import { Compute } from './compute';

/**
 * Represents an object with string keys and values of any type.
 */
export type AnyRecord = { [K: string]: any };

/**
 * Represents an object with string keys and values of an unknown type.
 * Safer than `AnyRecord`.
 */
export type UnknownRecord = { [K: string]: unknown };

/**
 * Extracts the resolved value type from a Promise.
 * @example PromiseValue<Promise<number>> // => number
 */
export type PromiseValue<T> = T extends Promise<infer R> ? R : T;

/**
 * Represents a value that could be a Promise or a direct value.
 */
export type MaybePromise<T> = Promise<T> | T;

/**
 * Flattens a complex intersection type into a single object for better readability.
 * @example
 * type R = Simplify<{ a: number } & { b: number }>;
 * // R is { a: number; b: number }
 */
export type Simplify<T> = [Exclude<T, BuiltIn>] extends [never]
  ? T
  : T extends ReadonlyArray<any>
    ? T
    : {
        [K in keyof T as Ternary<IsKnown<T[K]>, K>]: T[K];
      };

/**
 * Represents a function with any arguments and any return type.
 */
export type AnyFunction = ((...args: any) => any) | Function;

/**
 * Represents a value that can be a single item or an array of that item.
 */
export type MaybeArray<T> = T | T[];

export type IsAny<T> = 0 extends 1 & T ? true : false;

export type IsNever<T> = [T] extends [never] ? true : false;

export type IsUnion<T, U = T> = T extends U
  ? [U] extends [T]
    ? false
    : true
  : never;

export type IsNullable<T> =
  Extract<T, null | undefined> extends never ? false : true;

export type IsOptional<T> = Extract<T, undefined> extends never ? false : true;

export type IsUnknown<T> =
  IsNever<T> extends false
    ? T extends unknown
      ? unknown extends T
        ? IsAny<T> extends false
          ? true
          : false
        : false
      : false
    : false;

export type OnlyKnown<T> = IsKnown<T> extends true ? T : never;

export type IsKnown<T> =
  IsAny<T> extends true
    ? false
    : IsNever<T> extends true
      ? false
      : IsUnknown<T> extends true
        ? false
        : true;

/**
 * Returns Option if Value is not known.
 *
 * @example
 * ```ts
 * type num = CastUnknown<1, number>; // number
 * type str1 = CastUnknown<'123', number>; // '123'
 * type str2 = CastUnknown<'123', string>; // string
 * ```
 */
export type CastUnknown<Value, Option, Coerce extends Boolean = true> =
  IsKnown<Value> extends true
    ? IsUnknown<Value> extends false
      ? Coerce extends true
        ? [Exclude<Value, Option>] extends [never]
          ? Option
          : Value
        : Value
      : Option
    : Option;

export type Boolean = true | false;
/**
 * Shallow merge two types
 * @example
 * ```ts
 *  type test = Merge<{ a: 1; b: 3 }, { a: 2; c: 8 }> // { a:2, b:3, c:8 }
 * ```
 */
export type Merge<A, B, Level extends Depth = 'deep'> =
  //
  Level extends 'flat'
    ? A & B
    : A extends BuiltIn
      ? Merge<B, {}>
      : B extends BuiltIn
        ? A
        : {
            [K in keyof A as K extends keyof B ? never : K]: A[K];
          } & { [K in keyof B]: B[K] };

export type Primitive =
  | string
  | boolean
  | number
  | null
  | undefined
  | bigint
  | symbol;

export type Serializable =
  | Exclude<Primitive, bigint | symbol>
  | { [K: string]: Serializable }
  | ReadonlyArray<Serializable>;

export type SerializableOnly<T> = {
  [K in keyof T as T[K] extends Serializable ? K : never]: T[K] extends unknown
    ? T[K]
    : never;
};

export type SerializableKeys<T> = AsString<keyof SerializableOnly<T>>;

export type Writable<T> =
  T extends ReadonlyArray<any>
    ? T
    : {
        -readonly [K in keyof T]: T[K] extends unknown ? T[K] : never;
      };

export type AsString<T> = T extends unknown
  ? T extends string
    ? T
    : never
  : never;

/**
 * Make some fields partial
 * @example
 *  PartialFields<{ id: string, email:string, meta: object }, ['id'], ['meta']>
 *  // => id is now optional and meta was omitted:
 *        { id?: string, email: string }
 */
export type PartialFields<
  T,
  Optionals extends (keyof T)[] = [],
  Exclude extends (keyof T)[] = [],
> = Simplify<
  Omit<
    {
      [P in keyof T as P extends AsString<Optionals[number]> ? never : P]: T[P];
    } & {
      [K in AsString<Optionals[number]>]?: T[K extends keyof T ? K : never];
    },
    AsString<Exclude[number]>
  >
>;

export type Depth = 'flat' | 'deep';

export type Literal = string | number | bigint | boolean;

export type BuiltIn =
  | Literal
  | Function
  | Error
  | Date
  | { readonly [Symbol.toStringTag]: string }
  | RegExp
  | Generator;

export type Has<U extends any, U1 extends any> = [U1] extends [U] ? 1 : 0;

export type If<B extends 0 | 1, Then, Else = never> = B extends 1 ? Then : Else;
export type Ternary<B extends true | false, Then, Else = never> = B extends true
  ? Then
  : Else;

export type Key = string | number | symbol;

/**
 * Converts a union of types into an intersection of those types.
 * @example UnionToIntersection<{ a: 1 } | { b: 2 }> // => { a: 1 } & { b: 2 }
 */
export type UnionToIntersection<U> = (
  U extends unknown ? (k: U) => void : never
) extends (k: infer I) => void
  ? I
  : never;

export type ObjectEntries<T extends { [K: string]: any }> = {
  [K in AsString<keyof T>]: [K, T[K]];
}[AsString<keyof T>][];

/**
 * Converts nullable fields to optional fields
 * @example:
 *  NullableToPartial<{age: string|undefined}> // => { age?: string }
 */
export type NullableToPartial<T> =
  //
  T extends unknown
    ? T extends Primitive
      ? T
      : Compute<
          UnionToIntersection<
            | {
                -readonly [K in keyof T as IsOptional<T[K]> extends true
                  ? never
                  : K]-?: T[K];
              }
            | {
                -readonly [K in keyof T as IsOptional<T[K]> extends true
                  ? K
                  : never]?: T[K];
              }
          >
        >
    : never;

export type RemoveUnknownEntries<Obj> = {
  [K in keyof Obj as [OnlyKnown<Obj>] extends [never] ? never : K]: OnlyKnown<
    Obj[K]
  >;
};

/**
 * Join an array of values
 * @example:
 * type Str = Join<['a', 'b', 'c'], '#'>; // a#b#c
 */
export type Join<T extends unknown[], D extends string> = T extends []
  ? ''
  : T extends [string | number | null]
    ? `${T[0]}`
    : T extends [string | number | null, ...infer R]
      ? `${T[0]}${D}${Join<R, D>}`
      : string;

/**
 * Ask TS to re-check that `A1` extends `A2`.
 * And if it fails, `A2` will be enforced anyway.
 * Can also be used to add constraints on parameters.
 * @param A1 to check against
 * @param A2 to cast to
 * @returns `A1 | A2`
 * @example
 * ```ts
 * import {A} from 'ts-toolbelt'
 *
 * type test0 = A.Cast<'42', string> // '42'
 * type test1 = A.Cast<'42', number> // number
 * ```
 */
export type Cast<A1 extends any, A2 extends any> = A1 extends A2 ? A1 : A2;

