    10→ * @example
    11→ *  isType(new Date('BANANA'), 'date') // => false; value is an invalid date;
    12→ *  isType(1, 'number') // => true; value is a number
    13→ *  isType(undefined, 'number?') // => true; value matches type `number?`
    14→ *  isType(undefined, 'number') // => false; value should be a number
    15→ */
    16→export function isType<Type extends TypeDefinitionString>(
    17→  value: unknown,
    18→  definition: Type,
    19→): value is InferType<Type> {
    20→  return createType(definition).isValid(value);
    21→}
    22→
    23→/**
    24→ * Asserts that value is of type `Type`
    25→ * @param value
    26→ * @param definition
    27→ * @param parentFunction
    28→ * @param customMessage
    29→ *
    30→ *  @example
    31→ *  const x = ['banana'] as unknown;
    32→ *  assertType('string[]', x)
    33→ *  console.log(x) // typescript now infers x as string[]
    34→ *
    35→ *  @example:
    36→ *  // will throw 'Expected value to match type "string[]"; found an invalid "Number" instead.',
    37→ *  assertType('string[]', 1)
    38→ */
    39→export function invariantType<Type extends TypeDefinition>(
    40→  definition: Type,
    41→  value: unknown,
    42→  parentFunction?: Function,
    43→  /**
    44→   * Custom message
    45→   * Accepts replacements `$typename`, `$originalMessage` and `$definition`.
    46→   */
    47→  customMessage = `Expected value to match type "$definition"; found an invalid "$typename" instead.`
    48→): asserts value is InferType<Type> {
    49→  try {
    50→    createType(definition as never).parse(value);
    51→  } catch (e: any) {
    52→    const originalMessage = typeof e.message === 'string' ? e.message : '';
    53→
    54→    let newMessage = customMessage.replace(
    55→      /\$(definition|typename|originalMessage)/g,
    56→      substring => {
    57→        switch (substring) {
    58→          case '$definition': {
    59→            return definition;
    60→          }
    61→          case '$typename': {
    62→            return getTypeOf(value);
    63→          }
    64→          case '$originalMessage': {
    65→            return originalMessage;
    66→          }
    67→          default: {
    68→            return substring;
    69→          }
    70→        }
    71→      },
    72→    );
    73→
    74→    e.message = newMessage;
    75→    if (parentFunction) Error.captureStackTrace(e, parentFunction);
    76→    throw e;
    77→  }
    78→}
