     1→/**
     2→ * @file Plugin Prettier para padronizar quebras de linha (multi-line)
     3→ * O objetivo é estabilizar diffs em code reviews e melhorar a legibilidade,
     4→ * reduzindo inconsistências e rigidez do `printWidth` padrão do Prettier.
     5→ *
     6→ * Regras principais:
     7→ * 1. Garante chaves (`{}`) em `IfStatement` com condições longas.
     8→ * 2. Aplica multi-line em `ArrayExpression` se `elements.length > arrayWrapThreshold`.
     9→ * 3. Aplica multi-line em `ObjectExpression` se `properties.length > objectWrapThreshold`.
    10→ * 4. Aplica multi-line em `TSTypeLiteral` se `members.length > objectWrapThreshold`.
    11→ * 5. Aplica multi-line em parâmetros de função (vários `FUNCTION_NODE_TYPES`) se
    12→ * o número de params (> 3) ou o comprimento da string de params (> paramsPrintWidth)
    13→ * exceder os limites.
    14→ *
    15→ * @prettier
    16→ */
    17→import { doc } from 'prettier';
    18→import { printers as estreePrinters } from 'prettier/plugins/estree';
    19→
    20→const originalEstreePrinter = estreePrinters.estree;
    21→const { group, indent, line, softline, join, ifBreak } = doc.builders;
    22→
    23→const DEFAULT_THRESHOLD = 1;
    24→const DEFAULT_CONDITION_PRINT_WIDTH = 50;
    25→
    26→// A set of function-like node types that have a `params` property.
    27→const FUNCTION_NODE_TYPES = new Set([
    28→  'FunctionDeclaration',
    29→  'FunctionExpression',
    30→  'ArrowFunctionExpression',
    31→  'ObjectMethod',
    32→  'ClassMethod',
    33→  'TSDeclareMethod',
    34→  'TSFunctionType',
    35→  'TSMethodSignature',
    36→]);
    37→
    38→/**
    39→ * Creates a wrapped printer that applies custom formatting rules.
    40→ * @param {object} originalPrinter - The original Prettier printer to wrap.
    41→ * @returns {object} The new printer with the overridden print function.
    42→ */
    43→function createWrappedPrinter(originalPrinter) {
    44→  return {
    45→    ...originalPrinter,
    46→    print(
    47→      path,
    48→      options,
    49→      print
    50→    ) {
    51→      const node = path.getValue();
    52→
    53→      function getText() {
    54→        return (getText.cache = getText.cache ?? options.originalText.slice(...node.range));
    55→      }
    56→
    57→      // function getParamWidth() {
    58→      //   return (getParamWidth.cache =
    59→      //     getParamWidth.cache ?? getText().match(/^[^)]+\)/)?.[0].length);
    60→      // }
    61→
    62→      // Determine thresholds from options.
    63→      const multilineWrapThreshold = asInt(options.multilineWrapThreshold, DEFAULT_THRESHOLD);
    64→      const objectWrapThreshold = asInt(options.objectWrapThreshold, multilineWrapThreshold);
    65→      const arrayWrapThreshold = asInt(options.arrayWrapThreshold, objectWrapThreshold);
    66→      // prettier-ignore
    67→      const paramsPrintWidth = asInt(options.paramsPrintWidth, DEFAULT_CONDITION_PRINT_WIDTH);
    68→
    69→      const trailingComma =
    70→        options.trailingComma === 'all' || options.trailingComma === 'es5' ? ifBreak(',', '') : '';
    71→
    72→      // Handle IfStatement to enforce braces
    73→      if (
    74→        node?.type === 'IfStatement' &&
    75→        node.consequent &&
    76→        node.consequent.type !== 'BlockStatement' &&
    77→        getText().split(')')[0].length > paramsPrintWidth
    78→      ) {
    79→        const parts = [
    80→          'if (',
    81→          softline,
    82→          path.call(print, 'test'),
    83→          softline,
    84→          ') ',
    85→          '{',
    86→          indent([
    87→            line,
    88→            path.call(print, 'consequent'),
    89→          ]),
    90→          line,
    91→          '}',
    92→        ];
    93→
    94→        if (node.alternate) {
    95→          parts.push(' else ', path.call(print, 'alternate'));
    96→        }
    97→
    98→        return parts;
    99→      }
   100→
   101→      // Handle ArrayExpression nodes.
   102→      if (node?.type === 'ArrayExpression' && node.elements.length > arrayWrapThreshold) {
   103→        return group(
   104→          [
   105→            '[',
   106→            indent([
   107→              line,
   108→              join(
   109→                [
   110→                  ',',
   111→                  line,
   112→                ],
   113→                path.map(print, 'elements'),
   114→              ),
   115→              trailingComma,
   116→            ]),
   117→            line,
   118→            ']',
   119→          ],
   120→          { shouldBreak: true },
   121→        );
   122→      }
   123→
   124→      // Handle ObjectExpression nodes.
   125→      if (node?.type === 'ObjectExpression' && node.properties.length > objectWrapThreshold) {
   126→        const objectDoc = group(
   127→          [
   128→            '{',
   129→            indent([
   130→              line,
   131→              join(
   132→                [
   133→                  ',',
   134→                  line,
   135→                ],
   136→                path.map(print, 'properties'),
   137→              ),
   138→              trailingComma,
   139→            ]),
   140→            line,
   141→            '}',
   142→          ],
   143→          { shouldBreak: true },
   144→        );
   145→
   146→        const parentNode = path.getParentNode();
   147→        if (parentNode?.type === 'ArrowFunctionExpression' && parentNode.body === node) {
   148→          return [
   149→            '(',
   150→            objectDoc,
   151→            ')',
   152→          ];
   153→        }
   154→
   155→        return objectDoc;
   156→      }
   157→
   158→      // Handle TSTypeLiteral nodes.
   159→      if (node?.type === 'TSTypeLiteral' && node.members.length > objectWrapThreshold) {
   160→        const trailingSemi = trailingComma ? ifBreak(';', '') : '';
   161→        return group(
   162→          [
   163→            '{',
   164→            indent([
   165→              line,
   166→              join(
   167→                [
   168→                  trailingSemi,
   169→                  line,
   170→                ],
   171→                path.map(print, 'members'),
   172→              ),
   173→              trailingSemi,
   174→            ]),
   175→            line,
   176→            '}',
   177→          ],
   178→          { shouldBreak: true },
   179→        );
   180→      }
   181→
   182→      const shouldBreakParams = (() => {
   183→        if (!FUNCTION_NODE_TYPES.has(node?.type)) {
   184→          return false;
   185→        }
   186→        return node.params?.length > 3 //|| getParamWidth() > paramsPrintWidth;
   187→      })();
   188→
   189→      // Handle function parameters.
   190→      if (shouldBreakParams) {
   191→        const doc = [];
   192→
   193→        // Handle method-specific prefixes.
   194→        if (
   195→          node.type === 'ClassMethod' ||
   196→          node.type === 'ObjectMethod' ||
   197→          node.type === 'TSDeclareMethod'
   198→        ) {
   199→          if (node.static) doc.push('static ');
   200→          if (node.accessibility) doc.push(node.accessibility, ' ');
   201→          if (node.abstract) doc.push('abstract ');
   202→          if (node.kind === 'get' || node.kind === 'set') {
   203→            doc.push(node.kind, ' ');
   204→          }
   205→        }
   206→
   207→        if (node.async) {
   208→          doc.push('async ');
   209→        }
   210→
   211→        if (node.type === 'FunctionDeclaration' || node.type === 'FunctionExpression') {
   212→          if (getText().match(/^(async )?function/)) {
   213→            doc.push('function');
   214→          }
   215→
   216→          if (node.generator) {
   217→            doc.push('*');
   218→          }
   219→          if (node.id) {
   220→            doc.push(' ', path.call(print, 'id'));
   221→          }
   222→        } else if (node.key) {
   223→          doc.push(path.call(print, 'key'));
   224→        }
   225→
   226→        if (node.typeParameters) {
   227→          doc.push(path.call(print, 'typeParameters'));
   228→        }
   229→
   230→        // Custom logic to force-break parameters.
   231→
   232→        doc.push(
   233→          group(
   234→            [
   235→              '(',
   236→              shouldBreakParams
   237→                ? indent([
   238→                  line,
   239→                  join(
   240→                    [
   241→                      ',',
   242→                      line,
   243→                    ],
   244→                    path.map(print, 'params'),
   245→                  ),
   246→                ])
   247→                : path.map(print, 'params'),
   248→              line,
   249→              ')',
   250→            ],
   251→            { shouldBreak: true },
   252→          ),
   253→        );
   254→
   255→        if (node.returnType) {
   256→          doc.push(path.call(print, 'returnType'));
   257→        } else if (node.predicate) {
   258→          doc.push(path.call(print, 'predicate'));
   259→        }
   260→
