import {
  formatDate,
  setDefaultDateLocale,
  getDefaultDateLocale,
} from '../date-utils';

describe('date-utils', () => {
  beforeEach(() => {
    setDefaultDateLocale(null);
  });

  describe('formatDate', () => {
    test('formats date with simple pattern', () => {
      const sut = formatDate('2025-09-25T20:49:09.645Z', 'M');
      expect(sut).toEqual('9');
    });

    test('formats date with month abbreviation', () => {
      const sut = formatDate('2025-09-25T20:49:09.645Z', 'MMM');
      expect(sut).toEqual('Sep');
    });

    test('accepts Date object', () => {
      const date = new Date('2025-09-25T20:49:09.645Z');
      expect(formatDate(date, 'yyyy-MM-dd')).toEqual('2025-09-25');
    });

    test('accepts timestamp number', () => {
      const timestamp = new Date('2025-09-25T00:00:00.000Z').getTime();
      expect(formatDate(timestamp, 'yyyy')).toEqual('2025');
    });

    test('throws on invalid date string', () => {
      expect(() => formatDate('banana', 'MMM')).toThrow('Invalid date');
    });

    test('throws on invalid Date object', () => {
      expect(() => formatDate(new Date('invalid'), 'MMM')).toThrow(
        'Invalid date',
      );
    });
  });

  describe('locale support', () => {
    test('getDefaultDateLocale returns null by default', () => {
      expect(getDefaultDateLocale()).toBeNull();
    });

    test('setDefaultDateLocale sets the default locale', async () => {
      const { ptBR } = await import('date-fns/locale/pt-BR');
      setDefaultDateLocale(ptBR);
      expect(getDefaultDateLocale()).toBe(ptBR);
    });

    test('formatDate uses default locale when set', async () => {
      const { ptBR } = await import('date-fns/locale/pt-BR');
      setDefaultDateLocale(ptBR);
      const sut = formatDate('2025-09-25T20:49:09.645Z', 'MMM');
      expect(sut).toEqual('set');
    });

    test('formatDate locale option overrides default', async () => {
      const { ptBR } = await import('date-fns/locale/pt-BR');
      const { enUS } = await import('date-fns/locale/en-US');
      setDefaultDateLocale(ptBR);
      const sut = formatDate('2025-09-25T20:49:09.645Z', 'MMM', {
        locale: enUS,
      });
      expect(sut).toEqual('Sep');
    });

    test('setDefaultDateLocale(null) clears the locale', async () => {
      const { ptBR } = await import('date-fns/locale/pt-BR');
      setDefaultDateLocale(ptBR);
      setDefaultDateLocale(null);
      expect(getDefaultDateLocale()).toBeNull();
    });
  });
});

