import { assertString, isString, capitalize } from '../string-utils';

describe('string-utils', () => {
  describe('isString', () => {
    test('returns true for strings', () => {
      expect(isString('hello')).toBe(true);
      expect(isString('')).toBe(true);
    });

    test('returns false for non-strings', () => {
      expect(isString(123)).toBe(false);
      expect(isString(null)).toBe(false);
      expect(isString(undefined)).toBe(false);
      expect(isString({})).toBe(false);
      expect(isString([])).toBe(false);
    });
  });

  describe('assertString', () => {
    test('passes for valid strings', () => {
      expect(() => assertString('hello')).not.toThrow();
      expect(() => assertString('')).not.toThrow();
    });

    test('throws for non-strings', () => {
      expect(() => assertString(123)).toThrow('Expected string, got number');
      expect(() => assertString(null)).toThrow('Expected string, got null');
      expect(() => assertString(undefined)).toThrow(
        'Expected string, got undefined',
      );
      expect(() => assertString({})).toThrow('Expected string, got object');
    });

    test('throws for empty strings when notEmpty is true', () => {
      expect(() => assertString('', { notEmpty: true })).toThrow(
        'Expected non-empty string',
      );
      expect(() => assertString('   ', { notEmpty: true })).toThrow(
        'Expected non-empty string',
      );
    });

    test('passes for non-empty strings when notEmpty is true', () => {
      expect(() => assertString('hello', { notEmpty: true })).not.toThrow();
      expect(() => assertString('  hello  ', { notEmpty: true })).not.toThrow();
    });

    test('uses custom message when provided', () => {
      expect(() =>
        assertString(123, { message: 'Name must be a string' }),
      ).toThrow('Name must be a string');

      expect(() =>
        assertString('', { notEmpty: true, message: 'Name is required' }),
      ).toThrow('Name is required');
    });
  });

  describe('capitalize', () => {
    test('capitalizes first letter', () => {
      expect(capitalize('hello')).toBe('Hello');
      expect(capitalize('world')).toBe('World');
    });

    test('handles already capitalized strings', () => {
      expect(capitalize('Hello')).toBe('Hello');
    });

    test('handles single character', () => {
      expect(capitalize('a')).toBe('A');
    });

    test('handles empty string', () => {
      expect(capitalize('')).toBe('');
    });

    test('throws for non-strings', () => {
      expect(() => capitalize(123 as any)).toThrow('Expected string');
    });
  });
});

