    40→/**
    41→ * extract object keys with type inference
    42→ */
    43→export function objectKeys<Obj extends object>(
    44→  value: Obj,
    45→): Extract<keyof Obj, string>[] {
    46→  try {
    47→    return Object.keys(value) as never;
    48→  } catch (e) {
    49→    assertErrorLike(e);
    50→    throw moveStackTrace(e, objectKeys);
    51→  }
