    54→export function objectMap<const O extends object>(
    55→  object: O,
    56→): ObjectEntries<Writable<O>> & Writable<O> {
    57→  const list = objectEntries(object);
    58→  const proxyTarget = { ...object };
    59→  Object.setPrototypeOf(proxyTarget, Object.getPrototypeOf(list));
    60→
    61→  list.forEach((value, idx) => {
    62→    Object.defineProperty(proxyTarget, idx, {
    63→      value,
    64→      enumerable: false,
    65→      configurable: false,
    66→    });
    67→  });
    68→
    69→  return new Proxy(proxyTarget, {
    70→    get(target, prop, receiver) {
    71→      const value = Reflect.get(target, prop, receiver);
    72→
    73→      if (typeof value === 'function') {
    74→        function fn(...args: any[]) {
    75→          const value = Reflect.get(target, prop, receiver) as never;
    76→          return Reflect.apply(value, list, args);
    77→        }
    78→        const name = Object.getOwnPropertyDescriptor(list, prop);
    79→        if (name) Object.defineProperties(fn, { name });
    80→        return fn;
    81→      }
    82→
    83→      return value;
    84→    },
    85→  }) as never;
    86→}
